import java.util.*;
class MinStackMain{
    private int[] stack;
    private int[] minStack;
    private int capacity;
    private int top;
    private int mintop;

    MinStackMain(int capacity){
        this.capacity = capacity;
        stack = new int[capacity];
        minStack = new int[capacity];
        top = -1;
        mintop = -1;
    }

    public void push(int data){
        if(top == capacity - 1){
            System.out.println("Stack Overflow!");
        } else {
            stack[++top] = data;
            System.out.println(data);
            if(mintop == -1 || data <= minStack[mintop]){
                minStack[++mintop] = data;
            }
        }
    }

    public void pop(){
        if(top == -1){
            System.out.println("Stack Underflow!");
        } else {
            int p = stack[top--];
            if(p == minStack[mintop]){
                mintop--;
            }
            System.out.println("Popped: " + p);
        }
    }

    void top(){
        if(top == -1){
            System.out.println("Stack is Empty!");
        } else {
            System.out.println("Top element: " + stack[top]);
        }
    }

    public void getMin(){
        if(mintop != -1){
            System.out.println("Minimum element: " + minStack[mintop]);
        }
    }

    public void displayAll(){
        if(top == -1){
            System.out.println("Stack is Empty!");
        } else {
            System.out.print("Stack elements: ");
            for(int i = 0; i <= top; i++){
                System.out.print(stack[i] + " ");
            }
            System.out.println();
        }
    }

    public static void main(String[] args){
        Scanner sc = new Scanner(System.in);
        System.out.print("Enter stack capacity: ");
        int n = sc.nextInt();
        MinStackMain ms = new MinStackMain(n);

        while(true){
            System.out.println("1. Push\n2. Pop\n3. Top\n4. Get Min\n5. Display\n6. Exit");
            System.out.print("Choose option: ");
            int option = sc.nextInt();
            switch(option){
                case 1:
                    System.out.print("Enter value: ");
                    int temp = sc.nextInt();
                    System.out.print("Pushed: ");
                    ms.push(temp);
                    break;
                case 2:
                    ms.pop();
                    break;
                case 3:
                    ms.top();
                    break;
                case 4:
                    ms.getMin();
                    break;
                case 5:
                    ms.displayAll();
                    break;
                case 6:
                    return;
                default:
                    System.out.println("Invalid choice");
            }
        }
    }
}

package q11486;
import java.util.*;
public class CTJ11486 {
    static int precedence(char op){
        if (op == '^') return 3;
        if (op == '*' || op == '/') return 2;
        if (op == '+' || op == '-') return 1;
        return 0;
    }

    static String convert(String expr) {
        Stack<Character> stack = new Stack<>();
        StringBuilder output = new StringBuilder();

        for(int i = 0; i < expr.length(); i++){
            char ch = expr.charAt(i);

            if(Character.isLetterOrDigit(ch)){
                output.append(ch).append("");
            } else if(ch == '('){
                stack.push(ch);
            } else if(ch == ')'){
                while(!stack.isEmpty() && stack.peek() != '('){
                    output.append(stack.pop()).append("");
                }
                stack.pop();
            } else {
                while(!stack.isEmpty() && 
                     ((ch != '^' && precedence(stack.peek()) >= precedence(ch)) || 
                      (ch == '^' && precedence(stack.peek()) > precedence(ch)))) {
                    output.append(stack.pop()).append("");
                }
                stack.push(ch);
            }
        }
        while(!stack.isEmpty()){
            output.append(stack.pop()).append("");
        }
        return output.toString();
    }

    public static void main(String[] args){
        Scanner sc = new Scanner(System.in);
        String expr = sc.nextLine();
        System.out.println(convert(expr));
    }
}

