import java.util.*;
public class CircularQueueSimulation{
    static int front = -1, rear = -1;

    static boolean isEmpty(){
        return front == -1;
    }

    static boolean isFull(int n){
        return front == (rear+1)%n;
    }

    static void enqueue(int[] q, int x, int n) {
        if(isFull(n)) {
            System.out.println("Queue Overflow");
        } else {
            if(isEmpty())
                front = rear = 0;
            else
                rear = (rear + 1) % n;
            q[rear] = x;
        }
    }

    static void dequeue(int[] q, int n){
        if(isEmpty()){
            System.out.println("Queue Underflow");
        } else {
            System.out.println("Dequeued: " + q[front]);
            if(front == rear) {
                front = rear = -1;
            } else {
                front = (front + 1) % n;
            }
        }
    }

    static void frontval(int[] q){
        System.out.println(isEmpty()?"Queue is Empty":q[front]);
    }

    static void rearval(int[] q){
        System.out.println(isEmpty()?"Queue is Empty":q[rear]);
    }

    static void display(int[] q, int n){
        if(isEmpty()){
            System.out.println("Queue is Empty");
        } else {
            System.out.print("Queue: ");
            for(int i = front; i != rear; i = (i + 1) % n){
                System.out.print(q[i] + " ");
            }
            System.out.print(q[rear]);
            System.out.println();
        }
    }

    public static void main(String[] args){
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int ops = sc.nextInt();
        int[] q = new int[n];
        for(int i = 0; i < ops; i++){
            String cmd = sc.next();
            if(cmd.equals("ENQUEUE")) enqueue(q,sc.nextInt(),n);
            else if(cmd.equals("DEQUEUE")) dequeue(q,n);
            else if(cmd.equals("FRONT")) frontval(q);
            else if(cmd.equals("REAR")) rearval(q);
            else if(cmd.equals("DISPLAY")) display(q,n);
        }
    }
}

