public class MergePointLinkedList {
    public static Node createList(int arr[]){
        Node dummy = new Node(-1);
        Node tail = dummy;
        for(int i = 0; i < arr.length; i++){
            tail.next = new Node(arr[i]);
            tail = tail.next;
        }
        return dummy.next;
    }

    public static Integer findMergePoint(Node link1, Node link2){
        Node l1 = link1;
        Node l2 = link2;
        while(l1 != null && l2 != null) {
            if(l1.data < l2.data) {
                l1 = l1.next;
            } else if(l1.data > l2.data) {
                l2 = l2.next;
            } else {
                return l1.data;
            }
        }
        return null;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        // Input for first linked list
        int n1 = sc.nextInt();
        int[] list1Arr = new int[n1];
        for (int i = 0; i < n1; i++) {
            list1Arr[i] = sc.nextInt();
        }

        // Input for second linked list
        int n2 = sc.nextInt();
        int[] list2Arr = new int[n2];
        for (int i = 0; i < n2; i++) {
            list2Arr[i] = sc.nextInt();
        }

        Node head1 = createList(list1Arr);
        Node head2 = createList(list2Arr);
        Integer mergeValue = findMergePoint(head1, head2);

        if(mergeValue != null){
            System.out.println("Merge point is: " + mergeValue);
        } else {
            System.out.println("No merge point found");
        }
    }
}

