public class CTJ11806 {
    static class Node{
        int data;
        Node left;
        Node right;
        Node(int data) {
            this.data = data;
        }
    }

    public static Node insertOrder(int arr[], int i){
        if(i < arr.length) {
            Node root = new Node(arr[i]);
            root.left = insertOrder(arr, 2 * i + 1);
            root.right = insertOrder(arr, 2 * i + 2);
            return root;
        }
        return null;
    }

    public static void preOrder(Node root){
        if(root == null) {
            return;
        }
        System.out.print(root.data + " ");
        preOrder(root.left);
        preOrder(root.right);
    }

    public static void inOrder(Node root){
        if(root == null){
            return;
        }
        inOrder(root.left);
        System.out.print(root.data + " ");
        inOrder(root.right);
    }

    public static void postOrder(Node root){
        if(root == null) {
            return;
        }
        postOrder(root.left);
        postOrder(root.right);
        System.out.print(root.data + " ");
    }

    public static void main(String[] args){
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int arr[] = new int[n];
        for(int i = 0; i < n; i++){
            arr[i] = sc.nextInt();
        }
        Node root = insertOrder(arr, 0);

        System.out.print("Preorder: ");
        preOrder(root);
        System.out.println();

        System.out.print("Inorder: ");
        inOrder(root);
        System.out.println();

