public class CTJ11803 {
    public static boolean isValidBST(int[] arr, int index, int min, int max){
        if(index >= arr.length) return true;

        int val = arr[index];
        if(val <= min || val >= max) return false;

        return isValidBST(arr, 2*index+1, min, val) &&
               isValidBST(arr, 2*index+2, val, max);
    }

    public static void main(String[] args){
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int[] arr = new int[n];
        for(int i = 0; i < n; i++){
            arr[i] = sc.nextInt();
        }

        if(isValidBST(arr, 0, Integer.MIN_VALUE, Integer.MAX_VALUE)){
            System.out.println(1);
        } else {
            System.out.println(0);
        }
    }
}

package q11942;
import java.util.*;
public class CTJ11942 {
    static class Node{
        int data;
        Node left, right;
        Node(int data) {
            this.data = data;
        }
    }

    static Node createsBST(int[] arr){
        if(arr.length == 0 || arr[0] == -1) return null;
        Queue<Node> que = new LinkedList<>();
        Node root = new Node(arr[0]);
        que.add(root);
        int i = 1;

        while(!que.isEmpty()){
            Node curr = que.poll();
            if(i < arr.length && arr[i] != -1){
                curr.left = new Node(arr[i]);
                que.add(curr.left);
            }
            i++;
            if(i < arr.length && arr[i] != -1){
                curr.right = new Node(arr[i]);
                que.add(curr.right);
            }
            i++;
        }
        return root;
    }

    static boolean isLeaf(Node node) {
        return node.left == null && node.right == null;
    }

    static void printLeaves(Node root) {
        if(root == null) return;
        if(isLeaf(root)){
            System.out.print(root.data + " ");
            return;
        }
        printLeaves(root.left);
        printLeaves(root.right);
    }

    static void printLeft(Node node) {
        if (node == null || isLeaf(node)) return;
        System.out.print(node.data + " ");
        if(node.left != null) printLeft(node.left);
        else printLeft(node.right);
    }

    static void printRight(Node node) {
        if(node == null || isLeaf(node)) return;
        if (node.right != null)
            printRight(node.right);
        else 
            printRight(node.left);
        System.out.print(node.data + " ");
    }

    public static void main(String[] args){
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int[] arr = new int[n];
        for(int i = 0; i < n; i++){
            arr[i] = sc.nextInt();
        }

        Node root = createsBST(arr);
        System.out.print(root.data + " ");
        printLeft(root.left);
        printLeaves(root);
        printRight(root.right);
    }
}

