import java.util.*;
class WarehouseInventory {
    public static void main(String args[]){
        Scanner sc = new Scanner(System.in);
        HashMap<Integer, Integer> pro = new HashMap<>();

        int n = sc.nextInt();
        for(int i = 0; i < n; i++){
            int option = sc.nextInt();

            if(option == 1){
                int code = sc.nextInt();
                int qun = sc.nextInt();
                pro.put(code, qun);
                System.out.println("Inserted: " + code + " " + qun);
            } else if(option == 2){
                int code = sc.nextInt();
                if(pro.containsKey(code)) {
                    pro.remove(code);
                    System.out.println("Deleted " + code);
                } else {
                    System.out.println("Not Found");
                }
            } else if(option == 3){
                int code = sc.nextInt();
                if(pro.containsKey(code)) {
                    System.out.println("Found");
                } else {
                    System.out.println("Not Found");
                }
            } else if(option == 4){
                for(int j = 0; j < 10; j++){
                    System.out.print("Bucket " + j + ": ");
                    boolean e = true;
                    for(Map.Entry<Integer, Integer> en : pro.entrySet()){
                        if(en.getKey() % 10 == j) {
                            System.out.print("(" + en.getKey() + "," + en.getValue() + ") ");
                            e = false;
                        }
                    }
                    if(e){
                        System.out.print("empty");
                    }
                    System.out.println();
                }
            }
        }
    }
}

package q12050;
import java.util.*;
public class CTJ12050 {
    public static void main(String[] args){
        Scanner sc = new Scanner(System.in);
        HashMap<Integer, Integer> h = new HashMap<>();

        int n = sc.nextInt();
        int[] arr = new int[n];
        for(int i = 0; i < n; i++){
            arr[i] = sc.nextInt();
        }

        int target = sc.nextInt();
        for(int i = 0; i < n; i++){
            if(h.containsKey(target - arr[i])){
                System.out.println("Indices: " + h.get(target - arr[i]) + " " + i);
                return;
            }
            h.put(arr[i], i);
        }
        System.out.println("No pair found");
    }
}

package q12051;
import java.util.*;
class TrieDataStructure{
    public static void main(String[] args){
        Scanner sc = new Scanner(System.in);
        int q = sc.nextInt();
        HashSet<String> words = new HashSet<>();

        for(int i = 0; i < q; i++){
            int op = sc.nextInt();
            String word = sc.next();

            switch(op){
                case 1:
                    if(!words.contains(word)) {
                        words.add(word);
                        System.out.println("Inserted: " + word);
                    } else {
                        System.out.println(word + " already exists");
                    }
                    break;
                case 2:
                    if(words.contains(word)){
                        System.out.println("Found");
                    } else {
                        System.out.println("Not Found");
                    }
                    break;
                case 3:
                    if(words.contains(word)){
                        words.remove(word);
                        System.out.println("Removed: " + word);
                    } else {
                        System.out.println("Word not found");
                    }
                    break;
                default:
                    System.out.println("Invalid operation");
            }
        }
    }
}

